ALTER TABLE public.user_settings ADD COLUMN IF NOT EXISTS configuracoes_ponto jsonb DEFAULT '{"texto_explicativo": "OS HORÁRIOS PODEM SER INTEIROS OU QUEBRADOS DE MEIA EM MEIA HORA, OU SEJA, PODE SER 08:00 OU 08:30 E ASSIM POR DIANTE.\n\n- SE O FUNCIONÁRIO CHEGAR ENTRE 08:00 E 08:10, CALCULAR COMO SE TIVESSE CHEGADO ÀS 08:00.\n- SE O FUNCIONÁRIO CHEGAR ENTRE 08:11 E 08:40, CALCULAR COMO SE TIVESSE CHEGADO 08:30.\n- SE O FUNCIONÁRIO CHEGAR ENTRE 08:41 E 09:10, CALCULAR COMO SE TIVESSE CHEGADO ÀS 09:00 E ASSIM POR DIANTE.\n\nO mesmo raciocínio vale para o horário da saída.\n\nO horário do almoço deve ser sempre descontado no cálculo como 1 hora de almoço, não importa o horário que está preenchido na planilha, esse horário na planilha é simplesmente informativo e controle interno, nao é para pagamento.", "desconto_almoco": 1}'::jsonb;
